// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

contract TrustMarket {
    struct Transaction {
        uint256 txId;
        uint256 productId;
        address buyer;
        address seller;
        uint256 amount;
        uint256 timestamp;
    }

    struct Review {
        address reviewer;
        uint8 rating;
        string comment;
        uint256 timestamp;
    }

    mapping(address => uint256) public trustScores;
    mapping(uint256 => Transaction) public transactions; // txId -> Transaction
    mapping(uint256 => Transaction[]) public productTransactions; // productId -> Transactions
    mapping(uint256 => Review[]) public productReviews; // productId -> Reviews

    // To quickly verify if an address bought a specific product
    mapping(uint256 => mapping(address => bool)) public hasBought; 

    uint256 public transactionCount;

    event ProductPurchased(
        uint256 indexed transactionId,
        uint256 indexed productId,
        address indexed buyer,
        address seller,
        uint256 amount,
        uint256 timestamp
    );

    event ReviewAdded(
        uint256 indexed productId,
        address indexed reviewer,
        uint8 rating,
        string comment,
        uint256 timestamp
    );

    event TrustScoreUpdated(address indexed user, uint256 newScore);

    // Function to handle payments
    function purchaseProduct(uint256 _productId, address payable _seller) public payable {
        require(msg.value > 0, "Amount must be greater than 0");
        require(msg.sender != _seller, "Seller cannot buy their own product");

        transactionCount++;

        Transaction memory newTx = Transaction({
            txId: transactionCount,
            productId: _productId,
            buyer: msg.sender,
            seller: _seller,
            amount: msg.value,
            timestamp: block.timestamp
        });

        transactions[transactionCount] = newTx;
        productTransactions[_productId].push(newTx);
        hasBought[_productId][msg.sender] = true;

        // Transfer funds to seller
        (bool success, ) = _seller.call{value: msg.value}("");
        require(success, "Transfer failed");

        // Update Trust Scores: Add 5 points for successful interaction
        _updateTrustScore(msg.sender, 5);
        _updateTrustScore(_seller, 5);

        emit ProductPurchased(transactionCount, _productId, msg.sender, _seller, msg.value, block.timestamp);
    }

    function leaveReview(uint256 _productId, uint8 _rating, string memory _comment) public {
        require(hasBought[_productId][msg.sender], "Only verified buyers can leave a review");
        require(_rating >= 1 && _rating <= 5, "Rating must be between 1 and 5");

        Review memory newReview = Review({
            reviewer: msg.sender,
            rating: _rating,
            comment: _comment,
            timestamp: block.timestamp
        });

        productReviews[_productId].push(newReview);

        // Reward for leaving a review
        _updateTrustScore(msg.sender, 2);

        emit ReviewAdded(_productId, msg.sender, _rating, _comment, block.timestamp);
    }

    function getReviews(uint256 _productId) public view returns (Review[] memory) {
        return productReviews[_productId];
    }

    function getAllTransactions() public view returns (Transaction[] memory) {
        Transaction[] memory allTx = new Transaction[](transactionCount);
        for (uint i = 1; i <= transactionCount; i++) {
            allTx[i-1] = transactions[i];
        }
        return allTx;
    }

    function _updateTrustScore(address _user, uint256 _points) internal {
        if (trustScores[_user] == 0) {
            trustScores[_user] = 50 + _points;
        } else {
            trustScores[_user] += _points;
        }
        if (trustScores[_user] > 100) {
            trustScores[_user] = 100;
        }
        emit TrustScoreUpdated(_user, trustScores[_user]);
    }

    function getTrustScore(address _user) public view returns (uint256) {
        return trustScores[_user] == 0 ? 50 : trustScores[_user];
    }
}

